class Solution {
    public int longestSubsequence(String s, int k) {
        int n = s.length();
        int[] dp = new int[n + 1];
        dp[0] = 0;
        for (int i = 1; i <= n; i++) {
            if (s.charAt(i - 1) == '0') {
                dp[i] = dp[i - 1];
            } else {
                dp[i] = Math.max(dp[i - 1], i + 1);
            }
            for (int j = 1; j <= Math.min(i, k); j++) {
                dp[i] = Math.max(dp[i], dp[i - j] + j);
            }
        }
        return dp[n];
    }
}
```

